```
#include <iostream>
#include <algorithm>
#include <string>

using namespace std;

int levenshtein_distance(string s1, string s2) {
    const int m = s1.size();
    const int n = s2.size();
    int dp[m + 1][n + 1];

    for (int i = 0; i <= m; i++) {
        dp[i][0] = i;
    }

    for (int j = 0; j <= n; j++) {
        dp[0][j] = j;
    }

    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            dp[i][j] = min({dp[i - 1][j] + 1, dp[i][j - 1] + 1, dp[i - 1][j - 1] + (s1[i - 1] != s2[j - 1])});
        }
    }

    return dp[m][n];
}

int main() {
    string s1 = "kitten";
    string s2 = "sitting";
    cout << "Levenshtein distance between " << s1 << " and " << s2 << " is " << levenshtein_distance(s1, s2) << endl;
    return 0;
}
```

This implementation calculates the Levenshtein distance between two input strings `s1` and `s2`. It first initializes a dynamic programming table `dp` with the base cases for empty strings, and then fills in the table by iterating through the strings and comparing each pair of characters. The final value in the table is the minimum Levenshtein distance between the two strings.

